import { NextRequest, NextResponse } from "next/server";

import { signAccessToken } from "@/lib/auth/jwt";
import type { ApiErrorResponse } from "@skynet/sdk";

interface TokenRequestBody {
  sub?: string;
  username?: string;
  role?: "engineer" | "pm" | "designer" | "operator";
}

interface TokenResponse {
  accessToken: string;
  tokenType: "Bearer";
  expiresIn: "1h";
}

function badRequest(message: string): NextResponse<ApiErrorResponse> {
  return NextResponse.json(
    { error: { code: "BAD_REQUEST", message } },
    { status: 400 },
  );
}

export async function POST(request: NextRequest): Promise<NextResponse> {
  let body: TokenRequestBody;
  try {
    body = (await request.json()) as TokenRequestBody;
  } catch {
    return badRequest("Request body must be valid JSON");
  }

  if (!body.sub) {
    return badRequest("`sub` is required to issue a JWT");
  }

  try {
    const accessToken = await signAccessToken({
      sub: body.sub,
      username: body.username,
      role: body.role,
    });

    const response: TokenResponse = {
      accessToken,
      tokenType: "Bearer",
      expiresIn: "1h",
    };

    return NextResponse.json(response, { status: 201 });
  } catch (error) {
    const message =
      error instanceof Error
        ? error.message
        : "Server JWT configuration is missing";

    const apiError: ApiErrorResponse = {
      error: {
        code: "SERVER_MISCONFIGURED",
        message,
      },
    };

    return NextResponse.json(apiError, { status: 500 });
  }
}
import { describe, expect, it } from "vitest";

import { getBearerToken } from "./bearer";

describe("getBearerToken", () => {
  it("returns token when header is valid", () => {
    expect(getBearerToken("Bearer token-123")).toBe("token-123");
  });

  it("accepts case-insensitive auth scheme", () => {
    expect(getBearerToken("bearer token-123")).toBe("token-123");
  });

  it("returns null when header is missing", () => {
    expect(getBearerToken(null)).toBeNull();
  });

  it("returns null when scheme is not Bearer", () => {
    expect(getBearerToken("Basic token-123")).toBeNull();
  });
});
import { afterAll, beforeAll, describe, expect, it } from "vitest";

import { signAccessToken, verifyAccessToken } from "./jwt";

const originalJwtSecret = process.env.JWT_SECRET;

describe("jwt helpers", () => {
  beforeAll(() => {
    process.env.JWT_SECRET = "test-jwt-secret-value";
  });

  afterAll(() => {
    if (originalJwtSecret === undefined) {
      delete process.env.JWT_SECRET;
      return;
    }

    process.env.JWT_SECRET = originalJwtSecret;
  });

  it("signs and verifies an access token", async () => {
    const token = await signAccessToken({
      sub: "user_123",
      username: "momo",
      role: "engineer",
    });

    const payload = await verifyAccessToken(token);
    expect(payload).not.toBeNull();
    expect(payload?.sub).toBe("user_123");
    expect(payload?.username).toBe("momo");
  });

  it("returns null for malformed token", async () => {
    const payload = await verifyAccessToken("not-a-jwt");
    expect(payload).toBeNull();
  });
});
